import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  // Simplest case
  it.todo("empty grid stays empty -- [] -> []");

  // Single cell dies (underpopulation - 0 neighbors)
  it.todo("single live cell dies -- [(0,0)] -> []");

  // Rule 1: Underpopulation (live cell with < 2 neighbors dies)
  it.todo("two adjacent live cells both die (each has 1 neighbor) -- [(0,1),(1,1)] -> []");

  // Rule 4: Reproduction (dead cell with exactly 3 neighbors becomes alive)
  it.todo("dead cell with exactly 3 live neighbors becomes alive -- Rule 4 example yields [(0,0),(1,0),(0,1),(1,1)]");

  // Rule 2: Survival (live cell with 2 or 3 neighbors lives)
  it.todo("Rule 2 survival example -- center (1,1) survives with 3 neighbors yielding [(1,0),(1,1)] from given pattern");

  // Rule 3: Overpopulation (live cell with > 3 neighbors dies)
  it.todo("Rule 3 overpopulation example -- center (1,1) with 4 neighbors dies, yields four corners");

  // Block (still life)
  it.todo("block still life remains unchanged -- [(0,0),(1,0),(0,1),(1,1)] -> same");

  // Blinker (oscillator)
  it.todo("blinker oscillates vertical -> horizontal -- [(0,0),(0,1),(0,2)] -> [(-1,1),(0,1),(1,1)]");

  // Negative coordinates
  it.todo("handles negative coordinates -- blinker shifted into negative space oscillates correctly");
});

export type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  throw new Error("Not implemented");
}

